import { readFileSync } from 'node:fs';

const scorePath = process.argv[2] ?? 'reports/mutation/mutation-score.json';
const baselinePath = process.argv[3];
const breakThreshold = Number(process.argv[4] ?? '88');

const score = JSON.parse(readFileSync(scorePath, 'utf8'));
const baseline =
  baselinePath && baselinePath !== 'none' ? JSON.parse(readFileSync(baselinePath, 'utf8')) : null;

const lines = [
  '<!-- mutation-report -->',
  '## Mutation test report',
  '',
  formatSummary(score, baseline, breakThreshold),
  '',
  formatTable(score, baseline),
  '',
  '_Generated by the mutation testing workflow._',
];

process.stdout.write(`${lines.join('\n')}\n`);

function formatSummary(score, baseline, breakThreshold) {
  const passed = score.mutationScore >= breakThreshold;
  const thresholdLine = passed
    ? `Break threshold **${breakThreshold}%** — passed.`
    : `Break threshold **${breakThreshold}%** — **failed**.`;

  if (!baseline) {
    return `Mutation score: **${formatPercent(score.mutationScore)}** (covered code: **${formatPercent(score.mutationScoreBasedOnCoveredCode)}**). No baseline found on the base branch yet. ${thresholdLine}`;
  }

  const delta = round(score.mutationScore - baseline.mutationScore);
  const deltaLabel = formatDelta(delta);
  return `Mutation score: **${formatPercent(score.mutationScore)}** (${deltaLabel} vs base **${formatPercent(baseline.mutationScore)}**). Covered code: **${formatPercent(score.mutationScoreBasedOnCoveredCode)}** (${formatDelta(round(score.mutationScoreBasedOnCoveredCode - baseline.mutationScoreBasedOnCoveredCode))}). ${thresholdLine}`;
}

function formatTable(score, baseline) {
  const headers = ['| Metric | This PR |'];
  const separators = ['| --- | ---: |'];

  if (baseline) {
    headers[0] += ' Base | Δ |';
    separators[0] += ' ---: | ---: |';
  }

  const rows = [
    row('Mutation score', score.mutationScore, baseline?.mutationScore),
    row(
      'Covered code score',
      score.mutationScoreBasedOnCoveredCode,
      baseline?.mutationScoreBasedOnCoveredCode,
    ),
    row('Killed', score.killed, baseline?.killed, false),
    row('Timed out', score.timeout, baseline?.timeout, false),
    row('Survived', score.survived, baseline?.survived, false),
    row('No coverage', score.noCoverage, baseline?.noCoverage, false),
    row('Total mutants', score.totalMutants, baseline?.totalMutants, false),
  ];

  return [headers[0], separators[0], ...rows].join('\n');
}

function row(label, current, base, asPercent = true) {
  const currentValue = asPercent ? formatPercent(current) : String(current);
  if (base === undefined || base === null) {
    return `| ${label} | ${currentValue} |`;
  }

  const baseValue = asPercent ? formatPercent(base) : String(base);
  const delta = asPercent ? formatDelta(round(current - base)) : formatDelta(current - base, false);
  return `| ${label} | ${currentValue} | ${baseValue} | ${delta} |`;
}

function formatPercent(value) {
  return `${value.toFixed(2)}%`;
}

function formatDelta(value, signed = true) {
  if (value === 0) {
    return '0';
  }

  const prefix = signed && value > 0 ? '+' : '';
  return `${prefix}${Number.isInteger(value) ? value : value.toFixed(2)}`;
}

function round(value) {
  return Math.round(value * 100) / 100;
}
